-- ================================================-- IDENTIFICAÇÃO DE VALORES NULOS-- Tabela: track_in_competition-- Método: COUNT + WHERE + IS NULL-- ================================================SELECT 'track_id' AS coluna, COUNT(*) AS total_nulosFROM `smiling-axiom-475916-q8.spotify_2023.track_in_competition`WHERE track_id IS NULLUNION ALLSELECT 'in_apple_playlists', COUNT(*)FROM `smiling-axiom-475916-q8.spotify_2023.track_in_competition`WHERE in_apple_playlists IS NULLUNION ALLSELECT 'in_apple_charts', COUNT(*)FROM `smiling-axiom-475916-q8.spotify_2023.track_in_competition`WHERE in_apple_charts IS NULLUNION ALLSELECT 'in_deezer_playlists', COUNT(*)FROM `smiling-axiom-475916-q8.spotify_2023.track_in_competition`WHERE in_deezer_playlists IS NULLUNION ALLSELECT 'in_deezer_charts', COUNT(*)FROM `smiling-axiom-475916-q8.spotify_2023.track_in_competition`WHERE in_deezer_charts IS NULLUNION ALLSELECT 'in_shazam_charts', COUNT(*)FROM `smiling-axiom-475916-q8.spotify_2023.track_in_competition`WHERE in_shazam_charts IS NULLORDER BY total_nulos DESC;-- ================================================-- VERIFICAÇÃO DE OUTLIERS-- Tabela: track_in_spotify-- SAFE_CAST ignora valores inválidos retornando NULL-- ================================================SELECT  MIN(SAFE_CAST(streams AS INT64))               AS min_streams,  MAX(SAFE_CAST(streams AS INT64))               AS max_streams,  AVG(SAFE_CAST(streams AS INT64))               AS media_streams,  MIN(SAFE_CAST(in_spotify_playlists AS INT64))  AS min_playlists,  MAX(SAFE_CAST(in_spotify_playlists AS INT64))  AS max_playlists,  AVG(SAFE_CAST(in_spotify_playlists AS INT64))  AS media_playlists,  MIN(SAFE_CAST(released_year AS INT64))         AS min_ano,  MAX(SAFE_CAST(released_year AS INT64))         AS max_anoFROM `smiling-axiom-475916-q8.spotify_2023.track_in_spotify`WHERE streams IS NOT NULL  AND in_spotify_playlists IS NOT NULL;